import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import { FaEye, FaEyeSlash } from 'react-icons/fa';
import { UserPlus, User, Mail, Lock, ShieldCheck } from 'lucide-react';
import toast from 'react-hot-toast';

const RegisterPage = () => {
  const [data, setData] = useState({
    fullName: '',
    email: '',
    password: ''
  });
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { register } = useAuth(); // Assuming register logic in AuthContext
  const { theme } = useTheme(); 
  const navigate = useNavigate();

  const handleRegister = async (e) => {
    e.preventDefault();
    if (!data.fullName || !data.email || !data.password) return toast.error('ALL_FIELDS_REQUIRED');
    
    const toastId = toast.loading('INITIALIZING_IDENTITY_NODE...');
    setLoading(true);
    try {
      // Logic for node initialization via FastAPI
      await register(data);
      toast.success('IDENTITY_INITIALIZED', { id: toastId });
      navigate('/login'); 
    } catch (err) { 
      toast.error('GATE_REJECTION: REGISTRATION_FAILED', { id: toastId }); 
    } finally { 
      setLoading(false); 
    }
  };

  const styles = {
    // 🎯 FIX: flex-center ensures the card is in the middle of the screen
    container: { 
      minHeight: '85vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '2rem' 
    },
    // 💎 Terminal Card: Matches the compact Login Page structure
    card: { 
      width: '100%', 
      maxWidth: '420px', 
      padding: '3rem', 
      backgroundColor: 'var(--card-bg)', 
      borderRadius: '24px', 
      border: '1px solid var(--border-color)', 
      boxShadow: 'var(--shadow-soft)',
      position: 'relative',
      overflow: 'hidden'
    },
    headerIcon: {
      display: 'flex',
      justifyContent: 'center',
      marginBottom: '1.5rem',
      color: 'var(--primary-accent)'
    },
    title: { 
      fontSize: '2rem', 
      color: 'var(--text-main)', 
      marginBottom: '0.5rem', 
      textAlign: 'center',
      textTransform: 'uppercase',
      letterSpacing: '0.3em',
      fontWeight: '300'
    },
    subtitle: {
      textAlign: 'center',
      fontSize: '10px',
      color: 'var(--text-muted)',
      textTransform: 'uppercase',
      letterSpacing: '0.25em',
      marginBottom: '2.5rem'
    },
    inputGroup: { position: 'relative', marginBottom: '1.2rem', width: '100%' },
    label: {
      display: 'flex',
      alignItems: 'center',
      gap: '8px',
      fontSize: '10px',
      color: 'var(--primary-accent)',
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.1em',
      marginBottom: '8px',
      marginLeft: '4px'
    },
    input: { 
      width: '100%', 
      padding: '1rem 3.5rem 1rem 1rem', 
      backgroundColor: 'var(--input-bg)', 
      border: '1px solid var(--border-color)', 
      borderRadius: '12px', 
      color: 'var(--text-main)', 
      fontSize: '14px', 
      outline: 'none',
      transition: 'all 0.3s ease',
      boxSizing: 'border-box'
    },
    toggleBtn: { 
      position: 'absolute', 
      right: '15px', 
      bottom: '12px', 
      background: 'none', 
      border: 'none', 
      color: 'var(--text-muted)', 
      cursor: 'pointer', 
      fontSize: '1.1rem'
    },
    button: { 
      width: '100%', 
      padding: '1rem', 
      marginTop: '1.5rem', 
      backgroundColor: 'var(--primary-accent)', 
      color: '#000', 
      border: 'none', 
      borderRadius: '12px', 
      fontWeight: 'bold',
      textTransform: 'uppercase',
      letterSpacing: '0.2em',
      fontSize: '12px',
      cursor: 'pointer', 
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: '10px',
      transition: 'all 0.3s ease'
    },
  };

  return (
    <div style={styles.container} className="reveal-data">
      <div style={styles.card}>
        {/* Laser Scan Decor for Institutional Aesthetic */}
        <div className="absolute top-0 left-0 w-full h-[1px] bg-emerald-500/40 shadow-[0_0_15px_var(--accent-glow)] animate-scan" />
        
        <div style={styles.headerIcon}>
          <UserPlus size={42} />
        </div>

        <h2 style={styles.title}>Initialize</h2>
        <p style={styles.subtitle}>Node_ID: Setup // Identity_Protocol</p>

        <form onSubmit={handleRegister}>
          <div style={styles.inputGroup}>
            <label style={styles.label}><User size={12} /> Full_Identity</label>
            <input 
              type="text" 
              placeholder="Operator Name" 
              value={data.fullName} 
              onChange={(e) => setData({ ...data, fullName: e.target.value })} 
              style={styles.input} 
            />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}><Mail size={12} /> Registry_Email</label>
            <input 
              type="email" 
              placeholder="operator@finify.ai" 
              value={data.email} 
              onChange={(e) => setData({ ...data, email: e.target.value })} 
              style={styles.input} 
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}><Lock size={12} /> Security_Key</label>
            <input 
              type={showPass ? "text" : "password"} 
              placeholder="••••••••" 
              value={data.password} 
              onChange={(e) => setData({ ...data, password: e.target.value })} 
              style={styles.input} 
            />
            <button type="button" onClick={() => setShowPass(!showPass)} style={styles.toggleBtn}>
              {showPass ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? 'INITIALIZING...' : <><ShieldCheck size={16}/> Initialize_Node</>}
          </button>
        </form>

        <div style={{textAlign: 'center', marginTop: '2rem', paddingTop: '1.5rem', borderTop: '1px solid rgba(255,255,255,0.05)'}}>
            <Link to="/login" style={{color: 'var(--primary-accent)', fontSize: '10px', textTransform: 'uppercase', letterSpacing: '0.1em'}}>
              Access_Existing_Gate
            </Link>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
